TARGET = 768
current_count = len(final_panel_symbols)
print("Final gene panel count before padding:", current_count)

adata_pan_raw = scanpy.read_h5ad("../Cellular Data/Single Cell/Reference/raw_mechanical.h5ad").raw.to_adata()

# adata_raw = adata.raw.to_adata()

if current_count < TARGET:
    padding_needed = TARGET - current_count

    # vendor_overlap_symbols = find_hardware_overlap("../Cellular Data/Single Cell/Reference/10x5kPanel.csv",
    #                                           "../Cellular Data/Single Cell/Reference/nano6kPanel.csv")

    scanpy.pp.highly_variable_genes(
        adata_pan_raw,
        flavor='seurat_v3',  # Expects raw counts
        batch_key="batch_tissue",
        inplace=True,
    )

    # 3. Use 'variances_norm' to rank (This replaces 'dispersions_norm')
    hvg_results = adata_pan_raw.var

    # 4. Fill the 155-gene gap
    current_panel_set = set(final_panel_symbols)
    padding_candidates = [
        g for g in adata_pan_raw.var_names
        if g not in current_panel_set and g in adata_pan_raw.var_names
    ]

    # Rank by the normalized variance generated by seurat_v3
    top_padding = hvg_results.loc[padding_candidates].sort_values(by='variances_norm', ascending=False)
    padding_ids = list(top_padding.index[:(768 - len(final_panel_symbols))])

    final_768_panel = final_panel_symbols + padding_ids
    print(f"✅ Final Hardware Tensor locked at {len(final_768_panel)} integers.")
    print(final_768_panel)